macro.command:
const version = "1.1.0";

try {
    if (args[0] === "on") {
        // Apply half proficiency to skills that are not proficient
        const actor = args[1]?.actorId ? game.actors.get(args[1].actorId) : null;

        if (!actor) {
            console.error(`Half Proficiency Macro Error - Version ${version}: Actor data is missing.`);
            return;
        }

        // Iterate over all skills in the actor's system data
        for (const skill in actor.system.skills) {
            const skillData = actor.system.skills[skill];

            // If the skill proficiency multiplier is 0, grant half proficiency (0.5)
            if (skillData?.value === 0) {

                // Store the original multiplier value in actor flags (if not already stored)
                if (!actor.getFlag("n5eb", `originalMultiplier_${skill}`)) {
                    await actor.setFlag("n5eb", `originalMultiplier_${skill}`, skillData.value );
                }

                const updatedSkillData = foundry.utils.deepClone(skillData);
                updatedSkillData.value = 0.5;

                // Update the actor's skill with the new multiplier
                await actor.update({
                    [`system.skills.${skill}`]: updatedSkillData
                });
            }
        }

    } else if (args[0] === "off") {
        // Revert skills back to their original proficiency multipliers
        const actor = args[1]?.actorId ? game.actors.get(args[1].actorId) : null;

        if (!actor) {
            console.error(`Half Proficiency Macro Error - Version ${version}: Actor data is missing.`);
            return;
        }

        // Iterate over all skills in the actor's system data
        for (const skill in actor.system.skills) {
            const originalMultiplier = actor.getFlag("n5eb", `originalMultiplier_${skill}`);

            // If an original multiplier is found, revert to it
            if (originalMultiplier !== undefined) {

                const updatedSkillData = foundry.utils.deepClone(actor.system.skills[skill]);
                updatedSkillData.value  = originalMultiplier;

                await actor.update({
                    [`system.skills.${skill}`]: updatedSkillData
                });

                // Remove the stored original multiplier flag
                await actor.unsetFlag("n5eb", `originalMultiplier_${skill}`);
            }
        }
    }

} catch (err) {
    console.error(`Half Proficiency Macro Error - Version ${version}`, err);
}
